var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"하아, 하필 갑자기 비가 내리네. 일기예보엔 그런 얘기가 없었는데?","JPN":"はぁ、急に雨だなんて。天気予報では言ってなかったのに。","ENG":"*Sigh* It's raining all of a sudden. The weather forecast said nothing about this.","TWN":"哀，怎麼偏偏這個時候下雨，天氣預報都不準。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"하하… 그러게요. 괜히 견학 왔다가 폐잠수정에 꼼짝없이 갇혀버렸어요.","JPN":"はは……そうですね。見学に来ただけなのに、廃潜水艦の中に閉じ込められてしまいました。","ENG":"Hah hah... I know. This field trip wasn't a good idea after all. Now, we're stuck inside the abandoned submarine.","TWN":"哈哈…就是說，出來觀摩，結果被困在廢棄潛水艇裡。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"뭘 그렇게 빤히 쳐다보는 거야? 여기서 나갈 생각부터 해야지.","JPN":"何をそんなにじっと見てるの？　ここからどうやって出るかを考えないと。","ENG":"Why are you staring at me like that? Think about how to get out of here.","TWN":"你幹麼一直盯著我？先想想要怎麼離開吧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"서두를 필요 없지 않아요? 출격까지도 아직 시간은 많이 남았고.","JPN":"急ぐ必要はないと思いますよ？　出撃までまだ時間はたっぷりありますし。","ENG":"But we're not in rush for anything. We've got plenty of time before our deployment.","TWN":"急什麼呢？距離出擊時間還很充裕。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"정신 차려. 난 부함장이고, 넌 견습 오퍼레이터야.","JPN":"何を言っているの。私は副艦長で、あなたは見習いオペレーターよ。","ENG":"Get a grip. I'm a deputy commander, and you're my training operator.","TWN":"你放尊重點！我可是副艦長，而你只是個實習領航員！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"상관없지 않아요?","JPN":"関係ないでしょう？","ENG":"Does that really matter?","TWN":"那又如何？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L10_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なにを言ってるの！？","ENG":"W-what?","TWN":"你…你說什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"<color=#ffd34c>함선 밖에서는 계급장 떼고 싸워도 상관없다</color>. 부함장님께서 가르쳐 주신 거잖아요?","JPN":"<color=#ffd34c>艦船の外では階級章は関係ない</color>。副艦長が教えてくれたじゃないですか？","ENG":"\\"<color=#ffd34c>Ranks don't matter outside the ship.</color>\\" That's what you taught me, isn't it?","TWN":"這不是副艦長你教我的嗎？<color=#ffd34c>官階只有在艦船內管用</color>。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"너, 지금 나한테 말대꾸하는 거니?","JPN":"あなた、今上司に口答えしているの？","ENG":"Is that why you're talking the way you are right now?","TWN":"你現在是拿我的話來堵我嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"왜요? 제가 싫으세요?","JPN":"なぜですか？　俺のこと、嫌いですか？","ENG":"Why? Don't you like me?","TWN":"幹嘛這樣？你討厭我嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"그, 그건…!","JPN":"そ、それは……！","ENG":"I-I...","TWN":"我…！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"우, 우와아아…","JPN":"う、うわあああ……","ENG":"W-whoaaah!","TWN":"哇哇哇…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양~ 어젯밤에 유혹의 함교 챙겨 봤어?","JPN":"ニコルちゃ～ん、昨日の誘惑の艦橋、観た！？","ENG":"Nicole, did you watch The Bridge of Seduction episode last night?","TWN":"妮可～你昨天有追誘惑的艦橋嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL"},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 지금 재방송으로 보고 있었어요.","JPN":"あっ、今再放送を観ていました。","ENG":"Ah, I'm watching a rerun right now.","TWN":"沒有，我正在看重播～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아아, 그 장면이네. 완전 화끈한 씬인데. 보면서 한 잔 하지 않고는 못 버티겠더라구.","JPN":"ああ、あの場面ね。すごく熱いシーンだったわよね。\\n観ながら一杯飲まずにはいられなかったわ。","ENG":"Ah, it's that scene! So hot, isn't it? It made me want a drink; I felt so thirsty all of a sudden.","TWN":"喔喔！剛好是最精彩的地方！看到這邊就覺得不來一杯不行！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"맞아요. 처음엔 무슨 이런 불경한 막장 이야기가 다 있나 싶었는데, 두근두근해서 눈을 뗄 수가 없더라고요.","JPN":"そうです。最初はなんて不敬な話と思ったのですが、\\n今は毎回ドキドキして目が離せません。","ENG":"Yes. At first, I couldn't believe how ridiculous this story was, but now I can't keep my eyes off the screen.","TWN":"真的，一開始我還想說這是什麼不正經的狗血劇，結果太好看，眼睛根本離不開電視。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아앗, 그러고 보니 벌써 시간이…!","JPN":"あっ、もうこんな時間……！","ENG":"Ah, where did time go?","TWN":"哎呀，都這個時間啦…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어서 재료 준비해야겠어요.","JPN":"はやく仕込みを始めないと。","ENG":"I'd better go prep the ingredients.","TWN":"我要趕快去準備材料！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어때, 내가 추천한 드라마. 시간 가는 줄 모르겠지?","JPN":"どう？　アタシがおすすめしたドラマ。\\n観てると時間が経つのがあっという間よね？","ENG":"You so love this drama I recommended that you completely lost the track of time.","TWN":"如何？我推薦的劇不錯吧？會讓你看到忘記時間。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아아, 다니엘처럼 상관한테 거칠게 덤벼드는 직원 어디 없으려나? 나도 갖고 싶다~","JPN":"あー、ダニエルみたいに上司だろうがお構いなく\\nアプローチしてくるスタッフはいないかしら。うちに来てくれないかな～。","ENG":"Ah, why can't I find my own Daniel? I'd love someone to seduce me so aggressively!","TWN":"像丹尼爾那種會撲倒上司的員工要去哪找啊？我也好想要那種員工喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"왜, 왜 저를 보면서 말씀하시는 거죠?","JPN":"な、なぜ私を見ながらそんな話を……","ENG":"W-why are you looking at me as you say that?","TWN":"為…為什麼要看著我說？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"……하긴, 니콜 양은 너무 착해서 누굴 덮칠 그릇은 안 되겠네.","JPN":"……うーん、ニコルちゃんは優しすぎて誰かを襲うようなことはないわよね。","ENG":"Well, Nicole. You're too kind to be so aggressive.","TWN":"……也是，妮可那麼乖巧，怎麼可能撲倒誰呢～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼, 오늘 밤도 가게 잘 부탁해~","JPN":"じゃあ、今夜もお店をよろしくね～。","ENG":"Alright, then take good care of the shop tonight.","TWN":"那今天晚上店裡也要麻煩你囉～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 네… 하하…","JPN":"あ、はい……ハハハ……","ENG":"Okay... Hah hah...","TWN":"好喔…哈哈…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어디 보자… 오늘은 레인보우 니콜을 만들 성수가 다 떨어졌네요.","JPN":"どれどれ……今日はレインボーニコルを作るための聖水が在庫切れです。","ENG":"Let's see... Today, I ran out of holy water to make the Rainbow Nicole with.","TWN":"我看一下…現在聖水的庫存不夠今天的份量。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"주문 수량을 생각하면 개시 전에 잔뜩 만들어 둬야…","JPN":"オーダー数を考えると、オープン前にたくさん作っておかないと……","ENG":"Considering its popularity, I'd better make a lot of holy water before opening the shop...","TWN":"照現在平均每天客人點的數量，在開店前必須多預備一些聖水…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"성수를……","JPN":"聖水を……","ENG":"Holy water...","TWN":"聖水……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…으으,","JPN":"うう……","ENG":"... Bah!","TWN":"…天啊！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":" 제가 지금 무슨 짓을 하고 있는 거죠?","JPN":"私はいったい何をしているのでしょう。","ENG":" Seriously, what am I doing?","TWN":"我這是在幹嘛？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"술에 성수를 넣어서 팔고 있다니…….","JPN":"酒に聖水を混ぜて売っているとは……","ENG":"I'm making holy water to sell alcohol.","TWN":"竟然將聖水加在酒裡賣……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"게다가 순정만화랑 드라마에 빠져서는… 성서도 멀리하고 있었어요.","JPN":"それに少女漫画やドラマにハマって……聖書からも遠ざかっています。","ENG":"Not only that, I've been completely infatuated with romance comics and TV shows. I can't even remember the last time I read the Bible.","TWN":"然後還追少女漫畫跟追劇…根本把任務整個拋諸腦後！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이 사실이 알려진다면 여지 없이 파면이겠죠…….","JPN":"この事実が知られれば、間違いなく罷免になるでしょう……","ENG":"If the church learns about this, I'll be excommunicated...","TWN":"要是被發現我這麼荒唐，肯定會被拔掉驅魔師的職分吧……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아니… 이런 안일한 태도는 저 스스로 용납할 수 없어요.","JPN":"いや……こんな安易な態度は私自身も許せません。","ENG":"Most of all, I can't tolerate my own complacency.","TWN":"可惡…這種安逸的態度，連我自己都無法原諒我自己！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으음… 니콜. 목말라.","JPN":"うぅん……ニコル、喉渇いたぞ。","ENG":"Mm... Nicole, I'm thirsty.","TWN":"嗯…妮可，我口渴。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(…애초에 저 같은 사람에겐 퇴마사가 어울리지 않았던 걸지도 모르겠네요.)","JPN":"(……そもそも、私のような人間は\\nエクソシストに向いていなかったのかもしれません。)","ENG":"(... Maybe I'm not cut out to be an exorcist to begin with.)","TWN":"(…或許，我打從一開始就不適合當驅魔師。)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(아니, 퇴마사로서 악마를 돌보고 있다는 사실 자체가 죄악이 되는 거잖아요.)","JPN":"(いや、エクソシストとして悪魔の世話をしているという事自体が\\n罪悪に当たる行為。)","ENG":"(I'm also betraying my duty as one by taking care of a devil.)","TWN":"(搞什麼！身為驅魔師，卻在照顧一個小魔鬼，有什麼比這更糟的嗎？)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜~ 주스 줘~","JPN":"ニコル、ジュースちょ～だい。","ENG":"Nicole, I want some juice.","TWN":"妮可～我要喝果汁～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 사람의 마음의 단면을 본 것만으로, 그 사람이 살아온 삶 전부를 알 순 없지.","JPN":"その人の心の側面を見ただけで、\\nその人が生きてきた人生のすべてを知ることはできない。","ENG":"I can't tell everything about you just by talking to you though.","TWN":"只是片面知道對方的心，是無法完全認識對方的一生的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그렇다면 적성에 맞는 일이라는 것도 마찬가지 아닐까?","JPN":"それなら、適性がある仕事も同じじゃないかしら。","ENG":"But that also applies to what you do, doesn't it?","TWN":"應用在工作上不也是一樣的道理嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"짧은 시간 동안 하나의 단면만을 보고서 그 길이 전부 잘못됐다고 확신할 순 없는 거야.","JPN":"短時間で一つの側面だけを見て、\\nその道が全部間違っていると確信することはできないの。","ENG":"You can't tell if it's right or wrong after experiencing it only for a short period.","TWN":"這麼短的時間內，你對這份工作只有片面的認識，怎麼能夠確定這條路是錯的呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(어쩌면… 지금이라도 이 악마를 퇴치하고 제 죄를 깊이 뉘우친다면…)","JPN":"(もしかすると……今からでもこの悪魔を祓って己の罪を悔い改めたら……)","ENG":"(Maybe... if I exorcise this devil and repent...)","TWN":"(或許還來得及…現在消滅魔鬼認罪的話…)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(다시 원래대로 돌아가진 못하더라도…)","JPN":"(すべて元には戻れないとしても……)","ENG":"(I may not be able to go back to how I was before...)","TWN":"(就算無法回到原本的樣子…)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(속죄 정도는 할 수 있지 않을까요?)","JPN":"(贖罪くらいはできるのではないでしょうか？)","ENG":"(But I could be free from my own guilt, couldn't I?)","TWN":"(但起碼可以贖罪吧？)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"힉?!","JPN":"ひっ！？","ENG":"Heek?","TWN":"欸？！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무, 무슨 짓이냐! 감히 이 몸에게 그런 걸 들이밀다니!","JPN":"な、何をしておる！　吾輩にそんなものを突きつけるなんて！","ENG":"W-what are you doing? Why are you sticking that gun in my face?","TWN":"你這是在幹嘛！竟敢拿那種東西指著本王！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"미안해요, 모모.","JPN":"ごめんなさい、モモ。","ENG":"I'm sorry, Momo.","TWN":"莫莫，對不起。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"처음부터 당신은… 제 신념과 함께 공존할 수 없었어요.","JPN":"はじめからあなたは……私の信念との共存はできなかったのです。","ENG":"I knew from the beginning that... you couldn't coexist with my faith.","TWN":"打從一開始…你和我的信念就是無法共存的。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저에겐… 너무 늦기 전에 이 잘못을 바로잡을 의무가 있으니까요.","JPN":"私には……手遅れになる前に自分の過ちを正す義務がありますから。","ENG":"I have to put things right before it's too late.","TWN":"我現在有義務…要將這個錯誤導正！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜? 화… 화난 것이냐?","JPN":"ニコル？　お、怒っているのか？","ENG":"Nicole? A-are you... angry with me?","TWN":"妮可？你…是在生我的氣嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"미안하도다. 주스는 이 몸이 혼자서도 잘 따라 마실 수 있노라.","JPN":"すまない。ジュースは吾輩が自分で入れるべきだったのだ。","ENG":"I'm sorry. I'll get my juice on my own.","TWN":"對不起啦，果汁本王自己會去倒。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그, 그러니까…… 화내지 말거라.","JPN":"だ、だから……怒らないでくれ。","ENG":"S-so... please don't be angry.","TWN":"你……不要生氣啦～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이제 소용없어요.","JPN":"今更無駄です。","ENG":"It doesn't work anymore.","TWN":"來不及了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"악마가 그런 표정으로… 그렇게 말해도…","JPN":"悪魔がそんな表情で……そんなことを言っても……","ENG":"A devil looking like that... speaking like that...","TWN":"就算魔鬼裝出那種表情…說那種話…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Err?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"이봐. 그레모리라는 이름의 여자가 여기에 있나?","JPN":"なあ、グレモリーという名前の女はここにいるか？","ENG":"Hey, is that woman named Gremory here?","TWN":"我問你，這裡有個叫葛茉莉的女人嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"그 여자에게 상담을 좀 받고 싶은데.","JPN":"その女に相談事があるんだが。","ENG":"I need her advice on something.","TWN":"我想找她聊幾句。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄송합니다만, 손님. 아직 영업 개시까지는 시간이 조금…","JPN":"申し訳ございませんが、お客様。まだ営業開始まで時間が……","ENG":"I'm sorry, sir, but we're not open yet—","TWN":"不好意思，現在還不是營業時間…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……무슨 짓이죠?","JPN":"……何の真似ですか？","ENG":"What's the meaning of this?","TWN":"……這是在做什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"내가 너무 젠틀하게 말했나?","JPN":"俺の話し方がジェントルすぎたかもな。","ENG":"Perhaps I was too gentle with you.","TWN":"是我口氣太紳士嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"바텐더 주제에 손님 심기 거스르지 말고, 당장 그레모리에게 안내해.","JPN":"バーテンダーのくせに客に逆らうのか？　今すぐグレモリーのところに案内しろ。","ENG":"You're just a bartender. Stop messing with me and take me to Gremory now.","TWN":"一個小小的調酒師，別惹客人不開心，快點叫葛茉莉出來！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"날 찾고 있어?","JPN":"アタシを探しているの？","ENG":"Looking for me?","TWN":"找我嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"음? 언제부터 거기에 앉아 있었지?","JPN":"うん？　いつからそこに座っていたんだ？","ENG":"Mm? How long have you been sitting there?","TWN":"嗯？你什麼時候站在那裡的？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나야 술이 있는 곳이라면 어디에나 있지.","JPN":"アタシはお酒があるところならどこにでもいるのよ。","ENG":"For as long as we've carried alcohol.","TWN":"只要有酒的地方就有我～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"두 사람은 잠깐 밖에서 놀다 올래? 이 아저씨랑 잠깐 얘기 나눠야 할 것 같거든.","JPN":"二人は少しだけ外で時間をつぶしてきてくれる？\\nこのおじさんとちょっと話さないといけないみたい。","ENG":"Why don't you two go for a walk? This gentleman and I need to talk in private.","TWN":"你們兩個可以先出去玩嗎？我和這位先生有點事要談。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네… 알겠습니다.","JPN":"はい……わかりました。","ENG":"Well... Okay.","TWN":"喔…好的。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"말귀는 잘 알아듣는군.","JPN":"話が早いな。","ENG":"I can tell you're shrewd.","TWN":"算你識相！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"그럼 내가 여기에 온 이유도 알고 있나?","JPN":"じゃあ、俺がここに来た理由も知ってるか？","ENG":"Do you know why I'm here?","TWN":"那你知道我來這裡的理由嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"알게 뭐람. 술도 주문 안 한 사람인데.","JPN":"知らないわ。ねえ、店に来て注文もしないってどう思う？","ENG":"Why should I care? You haven't even ordered your drink yet.","TWN":"有什麼好知道的～連酒都不點一杯。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"……블랙 마티니로 하지.","JPN":"……ブラックマルティーニで。","ENG":"... A black martini, then.","TWN":"……那就來杯黑色馬丁尼吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머. 귀여운 취향이네.","JPN":"あら、可愛い好みね。","ENG":"Oh, you're sweeter than I thought.","TWN":"哇喔，這麼可愛～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"당신을 찾느라 애 좀 먹었어, <color=#ffd34c>라미아</color>.","JPN":"あんたを探すのに苦労したぞ、<color=#ffd34c>ラミア</color>。","ENG":"I've been looking for you, <color=#ffd34c>Lamia</color>.","TWN":"我找你找得好苦啊，<color=#ffd34c>拉米亞</color>。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"암흑가에서 알아주던 예언자. 망해가던 사업도 당신의 조언 한마디면 반드시 살아나지.","JPN":"暗黒街では名の知れた預言者。倒産寸前だった事業も、\\nあんたのアドバイスの一言で必ず生き返る。","ENG":"A prophet whose name is legendary in the underworld. Your advice can revive a business on its last legs.","TWN":"在黑幫之中口耳相傳的預言家，只要有你一句建言，就能叫快要倒閉的事業起死回生。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"평의회 중 몇 명인가가 당신 도움으로 그 자리까지 올라갔다는 일화는… 두 말할 필요 없이 유명하고 말이야.","JPN":"評議会の何人かがあんたのおかげでその地位に就いたという噂は……\\n言うまでもなく有名だからな。","ENG":"Also, it's an open secret that you helped a few members of the Dark Council reach where they're now.","TWN":"我聽說評議會中也有幾個傢伙，是在你的幫助之下才能爬到現在的位置…這應該不需要我再多說吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"그런 귀한 분이 이런 형편없는 술집에 숨어 있었으니, 지금껏 못 찾을 만도 하군.","JPN":"そんな有名人がこんなおんぼろ飲み屋に隠れていたなんて、\\nこりゃ見つけられないわけだ。","ENG":"Who knew such a valuable asset to the industry was hiding in a shabby watering hole like this?","TWN":"這麼厲害的角色，竟然躲在這種不起眼的小酒吧裡，難怪我都找不到你。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 이름은 이제 안 써. 요즘 다시 취미가 바뀌었거든.","JPN":"その名前はもう使わないわ。最近新しい趣味ができてね。","ENG":"I don't use that name anymore. I'm into a different hobby now.","TWN":"我的興趣又換了，所以名字也改了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"지금은 사랑의 조언가 그레모리라고 부르면 돼.","JPN":"今は愛のカウンセラー、グレモリーと呼んでちょうだい。","ENG":"Now, you can call me Gremory the Love Adviser.","TWN":"我現在是愛情專家 葛茉莉。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"심심하면 연애운은 봐 줄 수 있는데, 어때?","JPN":"暇なら恋愛運を占ってあげるけど、どう？","ENG":"I can foretell your luck in love if you want. What do you say?","TWN":"無聊的話，我可以幫你看看戀愛運，要嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"집어치워. 내가 원하는 건 하나야.","JPN":"ふざけるな。俺の望みは一つ。","ENG":"Cut the crap. There's only one thing I want from you.","TWN":"少跟我胡扯那些，我來找你的目的只有一個！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"당신이 가진 예언인지 뭔지 하는 능력으로 내 사업을 도와 주면 좋겠어.","JPN":"あんたのその預言かなにかの能力で、俺のビジネスを手伝ってくれ。","ENG":"I want you to use your fortune-telling skills to help me with my business.","TWN":"我希望借助你的超能力還什麼的，來幫助我的事業！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"망할 평의회 놈들이 이 변방에까지 개입한 뒤부터 우리가 독점하던 사업들이 줄줄이 넘어가고 있다고.","JPN":"クソみたいな評議会の連中がこの辺にまで介入し始めて、\\n俺らが独占していた事業が次々とそっちに流れている。","ENG":"That cursed Council expanded its reach all the way to this backwater place, stealing business from me.","TWN":"自從評議會那些該死的傢伙跑到這來後，原本我們獨佔的事業範圍，就一直在縮小！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 순진하긴. 내 조언의 대가가 뭔지는 모르고 온 모양이네.","JPN":"フフッ、甘いわね。アタシの助言の代償が何かは知らずに来たの？","ENG":"Hah hah. You're such an innocent soul. You don't know the price you have to pay for my advice, do you?","TWN":"呵呵，真是好傻好天真，你應該不知道想聽我的建言，要付出什麼樣的代價吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"돈이라면 얼마든지 주지.","JPN":"金ならいくらでもくれてやる。","ENG":"I'll give you as much money as you want.","TWN":"錢的話要多少都有！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"아마 다른 녀석들이 찾아와도 이 정도 액수는 부르지 못할 거야.","JPN":"他の連中が依頼したとしても、こんな額は提示できないだろう。","ENG":"And I bet no one else has been as generous as I am.","TWN":"我想其他人出的價應該不會比我高。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"그러니 협상에 괜한 시간 낭비하지 말자고.","JPN":"だから交渉のために時間を無駄にするのはやめようじゃないか。","ENG":"So, let's not waste our time on negotiating.","TWN":"我們就廢話少說…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"……없어.","JPN":"……ないわ。","ENG":"... No.","TWN":"……沒辦法。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"너처럼 흔해 빠진 녀석은 애초에 내 계약을 감당할 수 없다고.","JPN":"アナタのようなありふれた人間は、\\nそもそもアタシの契約に耐えられないって言ってるの。","ENG":"People like you are a dime a dozen. You can't handle a contract with me.","TWN":"像你這種小角色，是無法承擔我的契約的。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"내가 너무 젠틀한 태도로 접근했나?","JPN":"俺の態度があまりにもジェントルなせいで、まだわかっていないようだな。","ENG":"I was too gentle with you, wasn't I?","TWN":"我是不是表現得太紳士了？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"아. 그렇지.","JPN":"ああ、そうだな……","ENG":"Oh, right.","TWN":"喔，對了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"아까 그 모모라는 꼬마… 당신과 아주 친해 보이더군.","JPN":"さっきのモモというガキ……あんたとはずいぶん仲が良さそうだったな。","ENG":"That girl named Momo. She's pretty close to you, isn't she?","TWN":"剛剛那個叫莫莫的小鬼…和你感情很好的樣子。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"그 애가 다치는 걸 원하진 않겠지?","JPN":"あの子が怪我をするのは望んでいないだろ？","ENG":"You wouldn't want her to get hurt, would you?","TWN":"你應該不希望她受到什麼傷害吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"방금 그 대사. 의심의 여지 없는 삼류 악당이었어.","JPN":"今のそのセリフ。疑う余地のない三流悪党のものだったわ。","ENG":"That line you just said. So stereotypical from a third-rate villain like you.","TWN":"你剛剛那句台詞，完全就是街頭混混會說的話。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"미리 경고하지만, 그 앨 함부로 건드렸다간 오히려 너만 다치게 될 거야.","JPN":"先に言っておくけど、あの子に手を出して後悔するのはアナタのほうよ。","ENG":"Heed my warning: lay a hand on her, and you'll be sorry.","TWN":"我可是好心警告你，你要是敢動她，恐怕受傷的人會是你。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"큭큭, 역시 그쪽이 약점이었나. 반응 한 번 확실하구만.","JPN":"クク、やはりそれが弱点だったか。いい反応だ。","ENG":"Hah hah. So, she really is your weakness. Thank you for confirming that.","TWN":"呵呵，看你的反應就知道，那個小鬼果然就是你的弱點。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"실망이야. 암흑가의 전설적인 유명인사를 기대하고 왔는데… 애나 돌보는 술꾼이 되어 있을 줄이야.","JPN":"ガッカリだな。\\n暗黒街の伝説的な有名人を期待して来たんだが。\\nガキのお世話係の呑兵衛になっていたとは。","ENG":"I’m disappointed. I came to see a legendary figure of the underworld. Instead, I've found a drunk burdened with a child.","TWN":"真令人失望，黑幫裡的傳奇人物…結果竟然是個酒鬼保母！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"하지만 나는 능력만 쓸모 있으면 상관없어. 당신이 주정뱅이든, 애 딸린 아줌마든 말이지.","JPN":"だが俺は能力さえ役に立つなら構わない。\\nあんたが酔っぱらいだろうが、子連れのババアだろうがな。","ENG":"Luckily for you, I don't care if you're a drunk or burdened with a child, so long as you're good at what you're doing.","TWN":"不過我在乎的是能力，就算你是酒鬼或保母都無所謂。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_GUEST","text":{"KOREA":"내가 다시 올 때까지 어떤 게 현명한 선택일지 잘 생각해 보라고.","JPN":"俺がまた来るまでに、どうするのが賢明な選択なのかよく考えておけ。","ENG":"I'll come back later. Until then, think about what's best for you.","TWN":"我給你點時間考慮，等我下次來的時候，希望你可以給我一個滿意的答覆。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐야. 귀한 술을 시켜 놓고 한 모금도 안 마시다니.","JPN":"何よ。貴重なお酒を頼んでおいて一口も飲まないなんて。","ENG":"Tsk, he didn't even touch this precious cocktail.","TWN":"什麼嘛，點了這麼貴的酒，結果連一口都沒喝。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"……딸꾹.","JPN":"……ひくっ。","ENG":"*Hiccups!*","TWN":"……嗝。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};